@@ -262,10 +263,7 @@
 	if (ret == UMATCH_NONE)
 		return (ret);

-	umodem_get_caps(uaa->device, &cm, &acm);
-	if (!(cm & USB_CDC_CM_DOES_CM) ||
-	    !(cm & USB_CDC_CM_OVER_DATA) ||
-	    !(acm & USB_CDC_ACM_HAS_LINE))
+	if (umodem_get_caps(uaa, -1, &cm, &acm) == -1)
 		return (UMATCH_NONE);

 	return ret;
@@ -279,7 +277,6 @@
 	usbd_device_handle dev = uaa->device;
 	usb_interface_descriptor_t *id;
